    { id: 1, name: 'Alice' },  // Removed email from unauthenticated response
    { id: 2, name: 'Bob' },
  ]);
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});
```

---

### Summary

| Severity | Issue | Fix |
|----------|-------|-----|
| **High** | No security headers | Add `helmet()` |
| **High** | PII exposed without auth | Add authentication middleware |
| **Medium** | No rate limiting | Add `express-rate-limit` |
| **Medium** | No package.json / lockfile | Initialize with `npm init` and lock dependencies |
| **Low** | No CORS policy | Add explicit `cors()` config |
| **Low** | Hardcoded port | Use `process.env.PORT` |
| **Info** | No body parser limits | Add `express.json({ limit })` |

